import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import {Button, H1, H2, InputGroup, Toaster, Tooltip} from "@blueprintjs/core";
import { observer } from "mobx-react";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";
import axios from "axios";
import {IToaster, IToasterProps} from "@blueprintjs/core/lib/esm/components/toast/toaster";
import {OurToaster} from "./OurToaster";

export const Register: FunctionComponent = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [mail, setMail] = useState("");
  const [mailConfirm, setMailConfirm] = useState("");
  const [password, setPassword] = useState("");
  const [passwordConfirm, setPasswordConfirm] = useState("");
  // const test: string = ctx.store.menu;
  const lockButton = (
    <Tooltip content={`${showPassword ? "Hide" : "Show"} Password`}>
      <Button
        className="outline-style-d"
        icon={showPassword ? "unlock" : "lock"}
        intent={Intent.WARNING}
        minimal={true}
        onClick={() => setShowPassword(!showPassword)}
      />
    </Tooltip>
  );

  function registerSubmit(e: any): void {
    e.preventDefault();
    if (formIsCorrect()) {
      const user: any = {
        userId: null,
        role: "pending",
        password: password,
        firstName: firstName,
        lastName: lastName,
        mail: mail,
        birthDate: null,
        phone: null,
        address: null,
        zipCode: null,
        city: null,
        country: null
      }
      axios
        .post(`http://localhost:5000/users_pending/`, { user })
        .then(response => {
          console.log(response.data);
          console.log(ctx.store.session.name);
          alert('Utilisateur c')
        })
        .catch(error => {
          console.log(error);
        });
    }
  }

  function formIsCorrect(): boolean {
    if (!mail.match('^[a-zA-Z0-9.!#$%&\'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$')) {
      OurToaster.show({
        message: "Mail address isn't valid.",
        intent: Intent.DANGER
      });
      return false;
    }
    if (mail !== mailConfirm) {
      OurToaster.show({
        message: "Mail and mail confirm must be equals !",
        intent: Intent.DANGER
      });
      return false;
    }
    if (password.match('^(?=.*[A-z])(?=.*[A-Z])(?=.*[0-9])(?=.*[$@])(?!.*[iIoO])\\S{6,12}$')) {
      OurToaster.show({
        message: "Password need more complexity !\nIt must be 6 to 12 characters, with one digit, one" +
            " upper case letter and one special symbol !",
        intent: Intent.DANGER,
        timeout: 10000
      });
      return false;
    }
    if (password !== passwordConfirm) {
      OurToaster.show({
        message: "Password and password confirm must be equals !",
        intent: Intent.DANGER
      });
      return false;
    }
    return true;
  }

  function validateForm(): boolean {
    return mail.length > 0 && mailConfirm.length > 0 && password.length > 0 && passwordConfirm.length > 0 &&
        firstName.length > 0 && lastName.length > 0;
  }

  return (
    <div>
      <form onSubmit={registerSubmit}>
        <div className="login-inputgroup fx -c">
          <div className="fx -r">
            <InputGroup
              placeholder="First Name"
              required={true}
              value={firstName}
              onChange={(ev: any) => setFirstName(ev.currentTarget.value)}
            />
            <InputGroup
              placeholder="Last Name"
              required={true}
              value={lastName}
              onChange={(ev: any) => setLastName(ev.currentTarget.value)}
            />
          </div>

          <InputGroup
            placeholder="Mail address"
            required={true}
            value={mail}
            onChange={(ev: any) => setMail(ev.currentTarget.value)}
          />
          <InputGroup
            placeholder="Confirm mail address"
            required={true}
            value={mailConfirm}
            onChange={(ev: any) => setMailConfirm(ev.currentTarget.value)}
          />
          <InputGroup
            placeholder="Password"
            type="password"
            required={true}
            value={password}
            onChange={(ev: any) => setPassword(ev.currentTarget.value)}
          />
          <InputGroup
            placeholder="Confirm password"
            type="password"
            required={true}
            value={passwordConfirm}
            onChange={(ev: any) => setPasswordConfirm(ev.currentTarget.value)}
          />
          <Button
            className="outline-style-d"
            icon="tick-circle"
            type="submit"
            disabled={!validateForm()}
          >
            Create an account
          </Button>
        </div>
      </form>
    </div>
  );
};
